#!/usr/bin/env node
// Build script: embeds the MiniML stdlib sources into js/stdlib_sources.js
// for the browser playground. The self-hosted compiler (compiler_native.js)
// reads stdlib files through its readFile callback at compile time; in the
// browser those reads are served from this embedded map.
//
// (This replaces the old browser.js, which also bundled the retired JS
// bytecode VM — see roadmap #13c. The playground now has exactly one
// execution strategy: compiler_native.js compiles to JS, which runs as JS.)

const fs = require("fs");
const path = require("path");

const dir = __dirname;
const stdlibDir = path.join(dir, "..", "stdlib");

// Keep in sync with the compiler's stdlib load order (self_host/main.mml).
const STDLIB_FILES = [
  "builtins", "classes", "option_type", "iter", "map_class", "show",
  "byte", "rune", "math", "list", "array_extra", "result", "option",
  "buffer", "hash", "hashtbl", "ref", "dynarray", "map", "set",
  "enum", "seq", "fmt", "compat",
];

const stdlibSources = {};
for (const name of STDLIB_FILES) {
  stdlibSources[`stdlib/${name}.mml`] = fs.readFileSync(
    path.join(stdlibDir, `${name}.mml`),
    "utf-8"
  );
}

const bundle = `// MiniML stdlib sources - browser bundle (generated by build_stdlib_bundle.js)
(function(global) {
"use strict";

const STDLIB_SOURCES = ${JSON.stringify(stdlibSources)};

global.MiniML = Object.assign(global.MiniML || {}, {
  STDLIB_SOURCES: STDLIB_SOURCES,
});

})(typeof window !== "undefined" ? window : globalThis);
`;

const outPath = path.join(dir, "stdlib_sources.js");
fs.writeFileSync(outPath, bundle);
console.log(`Wrote ${outPath} (${(bundle.length / 1024).toFixed(1)} KB)`);
